mapper.select:
SELECT ft.流水编号 as transactionId, ft.账户编号 as accountId, ft.科目编号 as subjectId, fs.科目编码 as subjectCode, fs.科目名称 as subjectName, fs.科目类别 as subjectCategory, fs.全科目名称 as fullSubjectName, fs.余额方向 as balanceDirection, ft.交易日期 as transactionDate, ft.交易类型 as transactionType, ft.交易金额 as amount, ft.是否内部往来 as internalTransfer, 'ALL' as dataType FROM FUND_TRANSACTION ft LEFT JOIN FUND_SUBJECT fs ON ft.科目编号 = fs.科目编号 WHERE ft.账户编号 IN
#{accountId}
AND ft.交易日期 >= #{yearStartDate} AND ft.交易日期 <= #{yearEndDate} AND ft.是否内部往来 = 0 ORDER BY ft.交易日期, ft.流水编号
